const issue = $input.first().json.body.issue;
const repo = $input.first().json.body.repository;
const sender = $input.first().json.body.sender;

// Map GitHub labels to priority
const labels = (issue.labels || []).map(l => l.name);
let priority = 'Medium';
if (labels.some(l => ['critical', 'p0', 'urgent', 'blocker'].includes(l.toLowerCase()))) priority = 'Urgent';
else if (labels.some(l => ['bug', 'high', 'p1'].includes(l.toLowerCase()))) priority = 'High';
else if (labels.some(l => ['enhancement', 'feature', 'p2'].includes(l.toLowerCase()))) priority = 'Low';

// Determine type
let type = 'Task';
if (labels.some(l => l.toLowerCase().includes('bug'))) type = 'Bug';
else if (labels.some(l => ['feature', 'enhancement', 'feature request'].includes(l.toLowerCase()))) type = 'Feature';

const body = issue.body || '';
const truncatedBody = body.length > 2000 ? body.substring(0, 2000) + '...\n\n[Truncated - see GitHub for full description]' : body;

return [{
  json: {
    issueNumber: issue.number,
    issueTitle: issue.title,
    issueBody: truncatedBody,
    issueUrl: issue.html_url,
    issueState: issue.state,
    labels: labels.join(', '),
    priority,
    type,
    authorLogin: sender.login,
    authorAvatar: sender.avatar_url,
    repoName: repo.full_name,
    repoUrl: repo.html_url,
    createdAt: issue.created_at,
    assignees: (issue.assignees || []).map(a => a.login).join(', ') || 'Unassigned',
    milestone: issue.milestone?.title || 'None'
  }
}];
